import { sendTransactionSafely } from '../transaction.js';
import { LogLevel } from '../logger.js';
/**
 * Handles the execution of a transaction step item, including transaction submission and validation.
 */
export async function handleTransactionStepItem({ stepItem, step, wallet, setState, request, client, json, chainId, isAtomicBatchSupported, incompleteStepItemIndex, stepItems, onWebsocketFailed, statusControl }) {
    if (!stepItem.data) {
        throw `Step item is missing data`;
    }
    client.log(['Execute Steps: Begin transaction step for, sending transaction'], LogLevel.Verbose);
    // if chainId is present in the tx data field then you should relay the tx on that chain
    // otherwise, it's assumed the chain id matched the network the api request was made on
    const transactionChainId = stepItem.data?.chainId ?? chainId;
    const crossChainIntentChainId = chainId;
    stepItem.progressState = 'confirming';
    setState({
        steps: [...json.steps],
        fees: { ...json?.fees },
        breakdown: json?.breakdown,
        details: json?.details
    });
    // If atomic batch is supported and first item in step, batch all items in the step
    const transactionStepItems = isAtomicBatchSupported && incompleteStepItemIndex === 0
        ? stepItems
        : stepItem;
    await sendTransactionSafely(transactionChainId, transactionStepItems, step, wallet, (txHashes) => {
        client.log(['Execute Steps: Transaction step, got transactions', txHashes], LogLevel.Verbose);
        stepItem.txHashes = txHashes;
        setState({
            steps: [...json.steps],
            fees: { ...json?.fees },
            breakdown: json?.breakdown,
            details: json?.details
        });
    }, (internalTxHashes) => {
        stepItem.internalTxHashes = internalTxHashes;
        setState({
            steps: [...json.steps],
            fees: { ...json?.fees },
            breakdown: json?.breakdown,
            details: json?.details
        });
    }, onWebsocketFailed, request, {
        'relay-sdk-version': client.version ?? 'unknown'
    }, crossChainIntentChainId, () => {
        stepItem.progressState = 'validating';
        setState({
            steps: [...json.steps],
            fees: { ...json?.fees },
            breakdown: json?.breakdown,
            details: json?.details
        });
    }, json?.details, (receipt) => {
        stepItem.receipt = receipt;
        setState({
            steps: [...json.steps],
            fees: { ...json?.fees },
            breakdown: json?.breakdown,
            details: json?.details
        });
    }, (checkStatus) => {
        if (checkStatus != stepItem.checkStatus) {
            stepItem.checkStatus = checkStatus;
            if (checkStatus === 'pending' ||
                checkStatus === 'submitted' ||
                checkStatus === 'success') {
                stepItem.progressState = undefined;
            }
            setState({
                steps: [...json.steps],
                fees: { ...json?.fees },
                breakdown: json?.breakdown,
                details: json?.details
            });
        }
    }, statusControl);
}
